args.TargetContent:
"                          {/* Resumo Profissional estilo chat bubble */}
                          {talent.summary ? (
                            <div className="bg-slate-50/50 p-3 rounded-[5px] border border-slate-100 text-left relative">
                              <div className="flex justify-between items-center mb-1">
                                <h5 className="text-[8.5px] font-black text-slate-400 uppercase tracking-wider">Resumo Profissional</h5>
                                {talent.summary.length > 120 && (
                                  <button
                                    type="button"
                                    onClick={() => toggleSummary(talent.id)}
                                    className="text-[8px] font-black text-indigo-655 hover:text-indigo-800 uppercase tracking-wider outline-none cursor-pointer border-0 bg-transparent p-0"
                                  >
                                    {expandedSummaries[talent.id] ? 'Ver menos' : 'Ver mais'}
                                  </button>
                                )}
                              </div>
                              <p className={`text-[9.5px] font-semibold text-slate-500 leading-relaxed italic text-justify ${
                                expandedSummaries[talent.id] ? '' : 'line-clamp-2'
                              }`}>
                                "{talent.summary}"
                              </p>
                            </div>
                          ) : null}"
